# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()  # Critical for real-time monitoring
    print(msg, flush=True)  # -u flag compatibility

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 3: compute_correlations_with_bootstrap_ci")

        # =========================================================================
        # STEP 1: Load Input Data
        # =========================================================================
        # Expected: Correlation input data with RAVLT scores and theta scores
        # Purpose: Compute bivariate correlations between RAVLT and IRT theta scores

        log("[LOAD] Loading correlation input data...")
        input_file = RQ_DIR / "data" / "step02_correlation_input.csv"
        df = pd.read_csv(input_file)
        log(f"[LOADED] {input_file.name} ({len(df)} rows, {len(df.columns)} cols)")
        
        # Verify expected columns
        expected_cols = ["uid", "ravlt_total", "ravlt_pct_ret", "theta_free_recall", "theta_recognition"]
        missing = [c for c in expected_cols if c not in df.columns]
        if missing:
            raise ValueError(f"Missing columns: {missing}. Found: {list(df.columns)}")

        log(f"[VALIDATE] All expected columns present: {expected_cols}")
        log(f"[VALIDATE] Data shape: {df.shape}")

        # =========================================================================
        # STEP 2: Run Analysis Tool
        # =========================================================================
        # Tool: bootstrap_correlation_ci
        # What it does: Computes correlation with bootstrap confidence intervals
        # Expected output: Dictionary with r, ci_lower, ci_upper, etc.

        log("[ANALYSIS] Computing correlations with bootstrap confidence intervals...")
        
        # Parameters for bootstrap
        n_bootstrap = 1000
        confidence = 0.95
        method = "pearson"
        seed = 42
        
        log(f"[ANALYSIS] Bootstrap parameters: n={n_bootstrap}, confidence={confidence}, method={method}, seed={seed}")
        
        # Convert to numpy arrays for bootstrap function
        ravlt_total = df['ravlt_total'].values
        ravlt_pct_ret = df['ravlt_pct_ret'].values
        theta_free_recall = df['theta_free_recall'].values
        theta_recognition = df['theta_recognition'].values

        # Define all correlation pairs to compute
        corr_pairs = [
            ('RAVLTtotal-FreeRecall', ravlt_total, theta_free_recall),
            ('RAVLTtotal-Recognition', ravlt_total, theta_recognition),
            ('RAVLTpctret-FreeRecall', ravlt_pct_ret, theta_free_recall),
            ('RAVLTpctret-Recognition', ravlt_pct_ret, theta_recognition),
        ]

        corr_results = []
        for pair_name, x_arr, y_arr in corr_pairs:
            log(f"[ANALYSIS] Computing r({pair_name})...")
            result = bootstrap_correlation_ci(
                x=x_arr,
                y=y_arr,
                n_bootstrap=n_bootstrap,
                confidence=confidence,
                method=method,
                seed=seed
            )
            log(f"[ANALYSIS] r({pair_name}) = {result['r']:.4f} [{result['ci_lower']:.4f}, {result['ci_upper']:.4f}]")
            corr_results.append((pair_name, result))

        # =========================================================================
        # STEP 2b: Calculate p-values (Decision D068 requirement)
        # =========================================================================
        # Decision D068: Must provide both uncorrected and Bonferroni-corrected p-values

        log("[ANALYSIS] Calculating p-values for correlations...")

        n_obs = len(df)
        n_tests = len(corr_pairs)  # 4 tests for Bonferroni correction
        log(f"[ANALYSIS] Bonferroni correction for {n_tests} tests")

        p_uncorrected_list = []
        for pair_name, result in corr_results:
            r_val = result['r']
            if abs(r_val) >= 1.0:
                p_unc = 0.0 if abs(r_val) > 1.0 else 1.0
            else:
                t_val = r_val * np.sqrt((n_obs - 2) / (1 - r_val**2))
                p_unc = 2 * (1 - stats.t.cdf(abs(t_val), df=n_obs-2))
            p_uncorrected_list.append(p_unc)

        p_bonferroni_list = [min(p * n_tests, 1.0) for p in p_uncorrected_list]

        for i, (pair_name, _) in enumerate(corr_results):
            log(f"[ANALYSIS] {pair_name}: p_uncorrected={p_uncorrected_list[i]:.6f}, p_bonferroni={p_bonferroni_list[i]:.6f}")

        # =========================================================================
        # STEP 3: Save Analysis Outputs
        # =========================================================================
        # These outputs will be used by: Step 4 (Steiger Z-test) for process-specificity testing

        log("[SAVE] Compiling correlation results...")

        # Create results dataframe
        rows = []
        for i, (pair_name, result) in enumerate(corr_results):
            rows.append({
                'correlation_pair': pair_name,
                'r_value': result['r'],
                'ci_lower': result['ci_lower'],
                'ci_upper': result['ci_upper'],
                'p_uncorrected': p_uncorrected_list[i],
                'p_bonferroni': p_bonferroni_list[i],
                'n_obs': n_obs
            })
        correlation_results = pd.DataFrame(rows)
        
        # Save results
        output_file = RQ_DIR / "data" / "step03_correlation_results.csv"
        correlation_results.to_csv(output_file, index=False, encoding='utf-8')
        log(f"[SAVED] {output_file.name} ({len(correlation_results)} rows, {len(correlation_results.columns)} cols)")

        # =========================================================================
        # STEP 4: Run Validation Tool
        # =========================================================================
        # Tool: validate_correlation_test_d068
        # Validates: Decision D068 compliance (dual p-value reporting)
        # Threshold: Checks for required columns and proper structure

        log("[VALIDATION] Running validate_correlation_test_d068...")
        validation_result = validate_correlation_test_d068(
            correlation_df=correlation_results,
            required_cols=["correlation_pair", "r_value", "ci_lower", "ci_upper", "p_uncorrected", "p_bonferroni"]
        )

        # Report validation results
        # Expected: Validation should pass for D068 compliance
        if isinstance(validation_result, dict):
            for key, value in validation_result.items():
                log(f"[VALIDATION] {key}: {value}")
        else:
            log(f"[VALIDATION] {validation_result}")

        # Check if validation passed
        if validation_result.get('valid', False):
            log("[VALIDATION] [PASS] D068 compliance validated")
        else:
            log("[VALIDATION] [FAIL] D068 compliance issues found")
            if not validation_result.get('d068_compliant', True):
                log("[VALIDATION] Missing required dual p-value columns")

        log("[SUCCESS] Step 3 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)